open class DictationController: Disposable, AutoCloseable, DictationControllerInterface
{

    @Suppress("UNUSED_PARAMETER")
    /**
     * @suppress
     */
    constructor(withHandle: UniffiWithHandle, handle: Long) {
        this.handle = handle
        this.cleanable = UniffiLib.CLEANER.register(this, UniffiCleanAction(handle))
    }

    /**
     * @suppress
     *
     * This constructor can be used to instantiate a fake object. Only used for tests. Any
     * attempt to actually use an object constructed this way will fail as there is no
     * connected Rust object.
     */
    @Suppress("UNUSED_PARAMETER")
    constructor(noHandle: NoHandle) {
        this.handle = 0
        this.cleanable = null
    }
    constructor(`config`: DictationConfig) :
        this(UniffiWithHandle, 
    uniffiRustCall() { _status ->
    UniffiLib.uniffi_speech_clerk_ffi_fn_constructor_dictationcontroller_new(
    
        FfiConverterTypeDictationConfig.lower(`config`),_status)
}
    )

    protected val handle: Long
    protected val cleanable: UniffiCleaner.Cleanable?

    private val wasDestroyed = AtomicBoolean(false)
    private val callCounter = AtomicLong(1)

    override fun destroy() {
        // Only allow a single call to this method.
        // TODO: maybe we should log a warning if called more than once?
        if (this.wasDestroyed.compareAndSet(false, true)) {
            // This decrement always matches the initial count of 1 given at creation time.
            if (this.callCounter.decrementAndGet() == 0L) {
                cleanable?.clean()
            }
        }
    }

    @Synchronized
    override fun close() {
        this.destroy()
    }

    internal inline fun <R> callWithHandle(block: (handle: Long) -> R): R {
        // Check and increment the call counter, to keep the object alive.
        // This needs a compare-and-set retry loop in case of concurrent updates.
        do {
            val c = this.callCounter.get()
            if (c == 0L) {
                throw IllegalStateException("${this.javaClass.simpleName} object has already been destroyed")
            }
            if (c == Long.MAX_VALUE) {
                throw IllegalStateException("${this.javaClass.simpleName} call counter would overflow")
            }
        } while (! this.callCounter.compareAndSet(c, c + 1L))
        // Now we can safely do the method call without the handle being freed concurrently.
        try {
            return block(this.uniffiCloneHandle())
        } finally {
            // This decrement always matches the increment we performed above.
            if (this.callCounter.decrementAndGet() == 0L) {
                cleanable?.clean()
            }
        }
    }

    // Use a static inner class instead of a closure so as not to accidentally
    // capture `this` as part of the cleanable's action.
    private class UniffiCleanAction(private val handle: Long) : Runnable {
        override fun run() {
            if (handle == 0.toLong()) {
                // Fake object created with `NoHandle`, don't try to free.
                return;
            }
            uniffiRustCall { status ->
                UniffiLib.uniffi_speech_clerk_ffi_fn_free_dictationcontroller(handle, status)
            }
        }
    }

    /**
     * @suppress
     */
    fun uniffiCloneHandle(): Long {
        if (handle == 0.toLong()) {
            throw InternalException("uniffiCloneHandle() called on NoHandle object");
        }
        return uniffiRustCall() { status ->
            UniffiLib.uniffi_speech_clerk_ffi_fn_clone_dictationcontroller(handle, status)
        }
    }

    
    @Throws(DictationFfiException::class)override fun `cancelRecording`()
        = 
    callWithHandle {
    uniffiRustCallWithError(DictationFfiException) { _status ->
    UniffiLib.uniffi_speech_clerk_ffi_fn_method_dictationcontroller_cancel_recording(
        it,
        _status)
}
    }
    
    

    
    @Throws(DictationFfiException::class)override fun `loadModel`(`modelId`: kotlin.String)
        = 
    callWithHandle {
    uniffiRustCallWithError(DictationFfiException) { _status ->
    UniffiLib.uniffi_speech_clerk_ffi_fn_method_dictationcontroller_load_model(
        it,
        FfiConverterString.lower(`modelId`),_status)
}
    }
    
    

    
    @Throws(DictationFfiException::class)override fun `pushAudio`(`samples`: List<kotlin.Float>, `sampleRateHz`: kotlin.UInt, `channels`: kotlin.UShort)
        = 
    callWithHandle {
    uniffiRustCallWithError(DictationFfiException) { _status ->
    UniffiLib.uniffi_speech_clerk_ffi_fn_method_dictationcontroller_push_audio(
        it,
        FfiConverterSequenceFloat.lower(`samples`),FfiConverterUInt.lower(`sampleRateHz`),FfiConverterUShort.lower(`channels`),_status)
}
    }
    
    

    
    @Throws(DictationFfiException::class)override fun `setLanguageContext`(`context`: LanguageContext)
        = 
    callWithHandle {
    uniffiRustCallWithError(DictationFfiException) { _status ->
    UniffiLib.uniffi_speech_clerk_ffi_fn_method_dictationcontroller_set_language_context(
        it,
        FfiConverterTypeLanguageContext.lower(`context`),_status)
}
    }
    
    

    
    @Throws(DictationFfiException::class)override fun `setLanguageMode`(`mode`: LanguageMode, `manualLanguage`: kotlin.String?)
        = 
    callWithHandle {
    uniffiRustCallWithError(DictationFfiException) { _status ->
    UniffiLib.uniffi_speech_clerk_ffi_fn_method_dictationcontroller_set_language_mode(
        it,
        FfiConverterTypeLanguageMode.lower(`mode`),FfiConverterOptionalString.lower(`manualLanguage`),_status)
}
    }
    
    

    
    @Throws(DictationFfiException::class)override fun `setReplacementRules`(`rules`: List<ReplacementRule>)
        = 
    callWithHandle {
    uniffiRustCallWithError(DictationFfiException) { _status ->
    UniffiLib.uniffi_speech_clerk_ffi_fn_method_dictationcontroller_set_replacement_rules(
        it,
        FfiConverterSequenceTypeReplacementRule.lower(`rules`),_status)
}
    }
    
    

    
    @Throws(DictationFfiException::class)override fun `startRecording`()
        = 
    callWithHandle {
    uniffiRustCallWithError(DictationFfiException) { _status ->
    UniffiLib.uniffi_speech_clerk_ffi_fn_method_dictationcontroller_start_recording(
        it,
        _status)
}
    }
    
    

    
    @Throws(DictationFfiException::class)override fun `stopRecording`(): Transcript? {
            return FfiConverterOptionalTypeTranscript.lift(
    callWithHandle {
    uniffiRustCallWithError(DictationFfiException) { _status ->
    UniffiLib.uniffi_speech_clerk_ffi_fn_method_dictationcontroller_stop_recording(
        it,
        _status)
}
    }
    )
    }
    

    

    


    
    
    /**
     * @suppress
     */
    companion object
    
}


/**
 * @suppress
 */
public object FfiConverterTypeDictationController: FfiConverter<DictationController, Long> {
    override fun lower(value: DictationController): Long {
        return value.uniffiCloneHandle()
    }

    override fun lift(value: Long): DictationController {
        return DictationController(UniffiWithHandle, value)
    }

    override fun read(buf: ByteBuffer): DictationController {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: DictationController) = 8UL

    override fun write(value: DictationController, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}



