sealed class DictationFfiException(message: String): kotlin.Exception(message) {
        
        class ControllerUnavailable(message: String) : DictationFfiException(message)
        
        class Core(message: String) : DictationFfiException(message)
        

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<DictationFfiException> {
        override fun lift(error_buf: RustBuffer.ByValue): DictationFfiException = FfiConverterTypeDictationFfiError.lift(error_buf)
    }
}

/**
 * @suppress
 */
public object FfiConverterTypeDictationFfiError : FfiConverterRustBuffer<DictationFfiException> {
    override fun read(buf: ByteBuffer): DictationFfiException {
        
            return when(buf.getInt()) {
            1 -> DictationFfiException.ControllerUnavailable(FfiConverterString.read(buf))
            2 -> DictationFfiException.Core(FfiConverterString.read(buf))
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
        
    }

    override fun allocationSize(value: DictationFfiException): ULong {
        return 4UL
    }

    override fun write(value: DictationFfiException, buf: ByteBuffer) {
        when(value) {
            is DictationFfiException.ControllerUnavailable -> {
                buf.putInt(1)
                Unit
            }
            is DictationFfiException.Core -> {
                buf.putInt(2)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




